body:
Hi, I'm trying to use your tool to translate an uvm project to c++, and I use uvm_do_with to randomize the input sequence. But I found that it is not work. I also try to use the function "randomize()' but also not work. The code I write is here. How can I fix it?


```
class xx_seq_item extends uvm_sequence_item;
//data and control fields
rand bit [1:0] addr;
rand bit wr_en;
rand bit rd_en;
rand bit [7:0] wdata;
bit [7:0] rdata;

constraint addr cons{
soft addr inside{[2'b10:2'b11]};
soft wdata == 8'h5a;
}

\`uvm_object_utils_begin(xx_seq_item)
\`uvm_field_int(addr,UVM_ALL_ON)
\`uvm_field_int(wr_en,UVM_ALL_ON)
\`uvm_field_int(rd_en,UVM_ALL_ON)
\`uvm_field-int(wdata,UVM_ALL_ON)
\`uvm_object_utils_end

function new(string name = "xx_seq_item");
super.new(name);
endfunction
endclass

class wr_rd_sequence extends uvm_sequence#(xx_seq__item);
\`uvm_object_utils(wr_rd_sequence)
function new (string name = "wr_rd_sequence");
superl.new(name);
endfunction
virtual task body();
xx_seq_item wr_seq;
wr_seq = new("wr_seq");
repeat(10) begin
uvm do with(wr_seq, {"
wr_seq.addr == 2'b10;
wr_seq.wdata == 8'h5a;
});
uvm_info(get_type_name(), "00 wr_seq.print..",UVM_NONE)
uvm_info(get_type_name(), "11 wr_seq.print..",UVM_NONE)
wr_seq.print();
end
endtask
endclass
```

